import { ref, computed, onMounted } from 'vue';
import { ElMessage } from 'element-plus';
import { Plus, VideoPlay, Refresh, ArrowUp, ArrowDown, Delete, CircleCheck, CircleClose, Loading, Timer, Bottom, ArrowRight, QuestionFilled, Document, Reading, Cpu, DataAnalysis, Download } from '@element-plus/icons-vue';
import api from '@/api';

// 状态

export default {
  __name: 'ChainWorkflow',
  setup(__props, {
    expose: __expose
  }) {
    __expose();
    const showAddNode = ref(false);
    const showSaveWorkflow = ref(false);
    const showGuide = ref(false);
    const workflowName = ref('');
    const workflowDescription = ref('');
    const currentNode = ref(null);
    const isExecuting = ref(false);
    const executionProgress = ref(0);
    const executionStatus = ref('');
    const executionTime = ref(0);
    const currentExecutingNode = ref(null);
    const executionResults = ref([]);

    // 链式节点
    const chainNodes = ref([]);

    // 新节点配置
    const newNode = ref({
      type: 'analysis',
      name: '',
      template: ''
    });

    // 输入内容
    const workflowInput = ref('');

    // 可用模板
    const availableTemplates = [{
      label: '生成摘要',
      value: 'summary',
      type: 'analysis'
    }, {
      label: '提取要点',
      value: 'keypoints',
      type: 'analysis'
    }, {
      label: '识别研究空白',
      value: 'gaps',
      type: 'analysis'
    }, {
      label: '主题分析',
      value: 'topic',
      type: 'analysis'
    }, {
      label: '方法分析',
      value: 'method_analysis',
      type: 'analysis'
    }, {
      label: '生成代码',
      value: 'code',
      type: 'generation'
    }, {
      label: '生成报告',
      value: 'report',
      type: 'generation'
    }, {
      label: '文献综述',
      value: 'review',
      type: 'generation'
    }, {
      label: '改进建议',
      value: 'improvement',
      type: 'generation'
    }, {
      label: '质量评估',
      value: 'quality',
      type: 'evaluation'
    }, {
      label: '创新性评估',
      value: 'innovation',
      type: 'evaluation'
    }, {
      label: '方法评估',
      value: 'method',
